<script setup>import{computed,reactive,ref}from"vue";import{onShow}from"@dcloudio/uni-app";import{api,showError}from"../../services/api";import{requireLogin}from"../../services/session";const items=ref([]),show=ref(false),editing=ref(null),busy=ref(false);const today=()=>new Date().toLocaleDateString('en-CA'),blank=()=>({merchant:'',amount:'',invoice_date:today(),category:'交通',invoice_number:'',status:'pending',note:'',image_url:null}),form=reactive(blank());const total=computed(()=>items.value.reduce((s,x)=>s+Number(x.amount),0)),pending=computed(()=>items.value.filter(x=>x.status!=='reimbursed').reduce((s,x)=>s+Number(x.amount),0));const money=v=>Number(v||0).toLocaleString('zh-CN',{minimumFractionDigits:2}),status=v=>({pending:'待报销',submitted:'已提交',reimbursed:'已到账'}[v]);async function load(){if(!requireLogin())return;try{items.value=await api.reimbursements()}catch(e){showError(e)}}function create(){Object.assign(form,blank());editing.value=null;show.value=true}function edit(x){Object.assign(form,{...x,invoice_date:x.invoice_date.slice(0,10)});editing.value=x.id;show.value=true}async function save(){if(!form.merchant||!Number(form.amount))return uni.showToast({title:'请填写商户和金额',icon:'none'});busy.value=true;try{editing.value?await api.updateReimbursement(editing.value,{...form}):await api.createReimbursement({...form});show.value=false;await load()}catch(e){showError(e)}finally{busy.value=false}}function remove(x){uni.showModal({title:'删除报销',content:`删除“${x.merchant}”的记录？`,success:async r=>{if(r.confirm){await api.deleteReimbursement(x.id);await load()}}})}onShow(load);</script>
<template><view class="page"><view class="hero row between"><view><text class="eyebrow">发票报销</text><text class="title">进度一目了然</text></view><button class="btn primary small" @click="create">＋ 添加</button></view><view class="metrics"><view class="metric"><text>发票合计</text><text class="strong">¥{{money(total)}}</text></view><view class="metric"><text>尚未到账</text><text class="strong expense">¥{{money(pending)}}</text></view></view><view v-if="!items.length" class="card empty">还没有报销记录</view><view v-for="x in items" :key="x.id" class="card item" @click="edit(x)"><view><text class="merchant">{{x.merchant}}</text><text class="muted">{{x.invoice_date.slice(0,10)}} · {{x.category}} · {{x.invoice_number||'无发票号'}}</text><text :class="['pill',x.status]">{{status(x.status)}}</text></view><text class="money">¥{{money(x.amount)}}</text></view><view v-if="show" class="sheet-mask" @click.self="show=false"><view class="sheet"><view class="sheet-head"><text>{{editing?'编辑报销':'新增报销'}}</text><text @click="show=false">×</text></view><label class="field">开票商户<input v-model="form.merchant" class="input"/></label><label class="field">金额<input v-model="form.amount" class="input" type="digit"/></label><label class="field">发票日期<picker mode="date" :value="form.invoice_date" @change="form.invoice_date=$event.detail.value"><view class="picker">{{form.invoice_date}}</view></picker></label><label class="field">费用类别<input v-model="form.category" class="input"/></label><label class="field">状态<picker :range="['待报销','已提交','已到账']" @change="form.status=['pending','submitted','reimbursed'][$event.detail.value]"><view class="picker">{{status(form.status)}}</view></picker></label><label class="field">发票号码<input v-model="form.invoice_number" class="input"/></label><label class="field">备注<textarea v-model="form.note" class="textarea"/></label><view class="row"><button v-if="editing" class="btn danger" @click="remove(items.find(x=>x.id===editing));show=false">删除</button><button class="btn primary grow" :disabled="busy" @click="save">保存报销</button></view></view></view></view></template>
<style scoped>.hero>view{flex:1}.item{display:flex;justify-content:space-between;align-items:center}.merchant{display:block;font-size:31rpx;font-weight:800}.item .muted{display:block;margin:8rpx 0}.pill{font-size:21rpx}.pill.submitted{background:#fff0d8;color:#a76b1f}.pill.reimbursed{background:#e5f4eb;color:#39815c}.grow{flex:1}</style>


